// src/components/Home.js
import React from 'react';
import "../styles/Home.css";

const Home = () => {
  return (
    <section className="hero">
      <div className="overlay"></div>
      <div className="hero-content">
        <p className="tagline">Struggling with Your School or College Project?</p>
        <h1>
          <span>Your Project, </span>{" "}
          <span className="highlight">ProjectDuniya</span>{" "}
          <span>Make It Easy.</span>
        </h1>
        <p className="description">
          From simple models to final year projects — we deliver fast, affordable, and customized solutions.
          Trusted by 500+ students. Your success is our mission.
        </p>
        <div className="hero-buttons">
          <a href="#" className="btn primary">Get Started</a>
          <a href="#" className="btn secondary">Contact Now</a>
        </div>
      </div>
    </section>
  );
};

export default Home;
